"use client";
import { useRef } from "react";
import { motion, useInView } from "framer-motion";
import { team } from "@/lib/data/content";
import { Github, Twitter, Instagram, Youtube } from "lucide-react";

const socialIcons: Record<string, React.ReactNode> = {
  twitter: <Twitter size={14} />,
  github: <Github size={14} />,
  instagram: <Instagram size={14} />,
  youtube: <Youtube size={14} />,
};

const avatarColors = ["#1a0f2e", "#0e1a10", "#1a100a", "#0a121e"];
const avatarEmojis = ["👤", "👤", "👤", "👤"];

export default function TeamSection() {
  const ref = useRef<HTMLDivElement>(null);
  const isInView = useInView(ref, { once: true, margin: "-100px" });

  return (
    <section className="py-32 bg-fluke-bg" ref={ref}>
      <div className="max-w-7xl mx-auto px-6">
        {/* Heading */}
        <motion.div
          initial={{ opacity: 0, y: 30 }}
          animate={isInView ? { opacity: 1, y: 0 } : {}}
          transition={{ duration: 0.7 }}
          className="text-center mb-16"
        >
          <p className="font-orbitron text-xs tracking-[0.4em] text-fluke-yellow uppercase mb-3">
            The Crew
          </p>
          <h2 className="font-bebas text-5xl sm:text-7xl text-fluke-text">
            Meet the Team
          </h2>
        </motion.div>

        {/* Team grid */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
          {team.map((member, i) => (
            <motion.div
              key={member.id}
              initial={{ opacity: 0, y: 40 }}
              animate={isInView ? { opacity: 1, y: 0 } : {}}
              transition={{ duration: 0.6, delay: i * 0.12 }}
            >
              <div className="group relative rounded-2xl overflow-hidden bg-fluke-surface border border-fluke-yellow/10 hover:border-fluke-yellow/35 transition-all duration-400 p-6 flex flex-col items-center text-center card-hover">
                {/* Avatar */}
                <div
                  className="w-24 h-24 rounded-full mb-4 flex items-center justify-center text-4xl border-2 border-fluke-yellow/20 group-hover:border-fluke-yellow/50 transition-all duration-300 overflow-hidden relative"
                  style={{ background: avatarColors[i] }}
                >
                  <span>{avatarEmojis[i]}</span>
                  {/* Glow ring on hover */}
                  <div className="absolute inset-0 rounded-full opacity-0 group-hover:opacity-100 transition-opacity duration-500 glow-box-yellow-strong" />
                </div>

                {/* Info */}
                <h3 className="font-sora font-bold text-fluke-text group-hover:text-fluke-yellow transition-colors mb-1">
                  {member.name}
                </h3>
                <p className="font-orbitron text-xs tracking-wider text-fluke-yellow mb-3">
                  {member.role}
                </p>
                <p className="font-sora text-xs text-fluke-muted leading-relaxed mb-4 line-clamp-3 group-hover:line-clamp-none transition-all duration-300">
                  {member.bio}
                </p>

                {/* Skills */}
                <div className="flex flex-wrap gap-1.5 justify-center mb-4">
                  {member.skills.map((skill) => (
                    <span
                      key={skill}
                      className="text-[10px] font-sora px-2 py-0.5 rounded-full bg-fluke-bg border border-fluke-yellow/10 text-fluke-muted"
                    >
                      {skill}
                    </span>
                  ))}
                </div>

                {/* Socials */}
                <div className="flex gap-2">
                  {member.socials.map(({ platform, url }) => (
                    <a
                      key={platform}
                      href={url}
                      aria-label={platform}
                      className="w-7 h-7 rounded-lg bg-fluke-bg border border-fluke-yellow/10 flex items-center justify-center text-fluke-muted hover:text-fluke-yellow hover:border-fluke-yellow/40 transition-all duration-300"
                    >
                      {socialIcons[platform]}
                    </a>
                  ))}
                </div>
              </div>
            </motion.div>
          ))}
        </div>
      </div>
    </section>
  );
}
